CREATE DATABASE CUSTOMER_BEHAVOIR

USE CUSTOMER_BEHAVOIR

SELECT * FROM CUSTOMER_TRENDS

-- WHAT IS THE TOTAL REVENUE GENERATED BY MALE VS FEMALE COSTOMERS?
CREATE OR ALTER VIEW [REVENUE BY GENDER] AS
SELECT GENDER, SUM(PURCHASE_AMOUNT) AS REVENUE
FROM CUSTOMER_TRENDS
GROUP BY GENDER

SELECT * FROM [REVENUE BY GENDER]

-- WHICH CUSTOMERS USED A DISCOUNT BUT STILL SPENT MORE THAN THE AVERAGE PURCHASE AMOUNT?
CREATE OR ALTER VIEW [MORE THAN AVERAGE SPENDING CUSTOMERS] AS 
SELECT CUSTOMER_ID, PURCHASE_AMOUNT 
FROM CUSTOMER_TRENDS
WHERE DISCOUNT_APPLIED = 'YES' AND PURCHASE_AMOUNT > (SELECT AVG(PURCHASE_AMOUNT) FROM CUSTOMER_TRENDS)

SELECT * FROM [MORE THAN AVERAGE SPENDING CUSTOMERS]

-- WHICH ARE THE TOP 5 PRODUCTS WITH THE HIGHEST AVERAGE REVIEW RATING 
CREATE OR ALTER VIEW [TOP 5 PRODUCTS BY REVIEWS] AS
SELECT TOP 5 ITEM_PURCHASED, ROUND(AVG(REVIEW_RATING),2) AS [AVERAGE REVIEW RATING]
FROM CUSTOMER_TRENDS
GROUP BY ITEM_PURCHASED
ORDER BY [AVERAGE REVIEW RATING] DESC

SELECT * FROM [TOP 5 PRODUCTS BY REVIEWS]

-- COMPARE THE AVERAGE PURCHASE AMOUNTS BETWEEN SHIPPING TYPES
SELECT SHIPPING_TYPE, AVG(PURCHASE_AMOUNT) AS [AVERAGE PURCHASE AMOUNT]
FROM CUSTOMER_TRENDS
GROUP BY SHIPPING_TYPE

SELECT SHIPPING_TYPE, AVG(PURCHASE_AMOUNT) AS [AVERAGE PURCHASE AMOUNT]
FROM CUSTOMER_TRENDS
WHERE SHIPPING_TYPE IN ('STANDARD','EXPRESS')
GROUP BY SHIPPING_TYPE

-- DO SUBSCRIBED CUSTOMERS SPENT MORE? COMPARE AVERAGE SPENT AND TOTAL REVENUE BETWEEN SUBSCRIBERS AND NON-SUBSCRIBERS.
SELECT SUBSCRIPTION_STATUS, COUNT(CUSTOMER_ID) AS CUSTOMERS, AVG(PURCHASE_AMOUNT) AS [AVERAGE PURCHASE], SUM(PURCHASE_AMOUNT) AS [TOTAL REVENUE]
FROM CUSTOMER_TRENDS
GROUP BY SUBSCRIPTION_STATUS

-- WHICH 5 PRODUCTS HAVE THE HIGHEST PERCENTAGE OF PURCHASE WITH DISCOUNTS APPLIED? 
SELECT TOP 5 ITEM_PURCHASED,
ROUND(100 * SUM(CASE WHEN DISCOUNT_APPLIED = 'YES' THEN 1 ELSE 0 END) / COUNT(*), 2) AS [DISCOUNT RATE]
FROM CUSTOMER_TRENDS
GROUP BY ITEM_PURCHASED
ORDER BY [DISCOUNT RATE] DESC

-- SEGMENT CUSTOMERS INTO NEW, RETURNING AND LOYAL BASED ON THEIR TOTAL NUMBER OF PREVIOUS PURCHASES AND SHOW THE COUNT OF EACH SEGMENT 
WITH CUSTOMER_TYPE AS (
SELECT CUSTOMER_ID, PREVIOUS_PURCHASES,
CASE 
	WHEN PREVIOUS_PURCHASES = 1 THEN 'NEW CUSTOMER'
	WHEN PREVIOUS_PURCHASES BETWEEN 2 AND 10 THEN 'RETURNING CUSTOMER'
	ELSE 'LOYAL CUSTOMER'
	END AS CUSTOMER_SEGMENT 
FROM CUSTOMER_TRENDS
)
SELECT CUSTOMER_SEGMENT, COUNT(*) AS [NUMBER OF CUSTOMERS] 
FROM CUSTOMER_TYPE
GROUP BY CUSTOMER_SEGMENT

-- WHAT ARE THE TOP 3 MOST PURCHASED PRODUCTS WITHIN EACH CATEGORY 
WITH ITEM_COUNTS AS (
SELECT CATEGORY, ITEM_PURCHASED, COUNT(CUSTOMER_ID) AS [TOTAL ORDERS],
ROW_NUMBER() OVER (PARTITION BY CATEGORY ORDER BY COUNT(CUSTOMER_ID) DESC) AS ITEM_RANK
FROM CUSTOMER_TRENDS 
GROUP BY CATEGORY, ITEM_PURCHASED)

SELECT ITEM_RANK, CATEGORY, ITEM_PURCHASED, [TOTAL ORDERS] FROM ITEM_COUNTS WHERE ITEM_RANK < 4

-- ARE CUSTOMERS WHO ARE REPEAT BUYERS (MORE THAN 5 PREVOUS PURCHASES) ALSO LIKELY TO SUBSCRIBE?
SELECT SUBSCRIPTION_STATUS, COUNT(CUSTOMER_ID) AS REPEAT_BUYERS 
FROM CUSTOMER_TRENDS
WHERE PREVIOUS_PURCHASES > 5
GROUP BY SUBSCRIPTION_STATUS 

--WHAT IS THE REVENUE CONTRIBUTION OF EACH AGE GROUP?
SELECT AGE_GROUP, SUM(PURCHASE_AMOUNT) AS [TOTAL REVENUE] FROM CUSTOMER_TRENDS
GROUP BY AGE_GROUP
ORDER BY [TOTAL REVENUE] DESC;